export const getToolsByCategory = (categoryId) =>
  categoryId === "all" ? TOOLS : TOOLS.filter((t) => t.category === categoryId);

export const getOSSCount = () => TOOLS.filter((t) => t.oss).length;

export const STATS = {
  total: TOOLS.length,
  oss: TOOLS.filter((t) => t.oss).length,
  categories: 14,
  freeCredits: "$600K+",
};
